import numpy as np

# {Introduce random perturbations to distances only for edges not in the local optimal tour, leveraging the inverse square of their usage frequency to encourage exploration without destabilizing established routes}

def update_edge_distance(edge_distance, local_opt_tour, edge_n_used):
    num_vertices = edge_distance.shape[0]
    updated_edge_distance = edge_distance.copy()

    # Create a set for easy lookup of edges in the local optimal tour
    local_opt_edges = {(local_opt_tour[i], local_opt_tour[(i + 1) % len(local_opt_tour)]) for i in range(len(local_opt_tour))}

    for i in range(num_vertices):
        for j in range(i + 1, num_vertices):
            # If edge is not in the local optimal tour
            if (i, j) not in local_opt_edges and (j, i) not in local_opt_edges:
                frequency = edge_n_used[i, j]
                perturbation_factor = 0.1 / (1 + frequency**2)
                perturbation = np.random.normal(0, perturbation_factor)
                updated_edge_distance[i, j] += perturbation
                updated_edge_distance[j, i] += perturbation

    return updated_edge_distance
